INSERT INTO conversation_lines (conversation_id, speaker, speaker_gender, speaker_role, sentence, furigana, translation, politeness, order_index, notes, notes_jp, tenant_id, is_deleted, is_active, created_at, created_by) VALUES
  ((SELECT id FROM _ids WHERE key='conv_rule_01_good_example_1'), 'zun', 'male', 'BD担当', 'お電話ありがとうございます。ティエンファット社、営業部のズンでございます。', 'おでんわありがとうございます。ティエンファットしゃ、えいぎょうぶのズンでございます。', 'Cảm ơn anh đã gọi điện. Tôi là Dũng, phòng kinh doanh, Cty Thiên Phát ạ.', 'formal', 0, '[お電話ありがとうございます] Câu chuẩn business khi nhận máy. Một số công ty quy định dùng 「はい、◯◯です」 cho call nội bộ ngắn. || [ティエンファット社、営業部のズン] Trật tự: Công ty → Phòng ban → Tên cá nhân. Không đảo ngược. || [でございます] Kính ngữ trang trọng hơn 「です」. Chuẩn cho receive call từ ngoài công ty.', '[お電話ありがとうございます] 受電の標準形。社内規定によっては「はい、◯◯です」も可。 || [ティエンファット社、営業部のズン] 順序は『会社名 → 部署名 → 氏名』。逆にしない。 || [でございます] 「です」より丁寧な敬語。社外受電の標準。', NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_01_good_example_1'), 'matsumoto', 'male', 'PM (白鷗株式会社)', 'お世話になっております。白鷗株式会社の松本と申します。', 'おせわになっております。はくおうかぶしきがいしゃのまつもとともうします。', 'Cảm ơn anh đã hỗ trợ. Tôi là Matsumoto bên Cty Hakuō ạ.', 'formal', 1, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_01_good_example_1'), 'zun', 'male', 'BD担当', '松本様、こちらこそいつもお世話になっております。', 'まつもとさま、いつもおせわになっております。', 'Anh Matsumoto, em luôn cảm ơn anh đã hỗ trợ ạ.', 'warm', 2, NULL, NULL, NULL, false, true, now(), 'system');
