  ((SELECT id FROM _ids WHERE key='conv_rule_05_good_example_0'), 'matsumoto', 'male', 'PM (白鷗株式会社)', '来週の打ち合わせの件で、火曜の15時に変更したいのですが。', NULL, 'Về cuộc họp tuần sau, tôi muốn đổi sang thứ Ba 15h ạ.', 'neutral', 0, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_05_good_example_0'), 'zun', 'male', 'BD担当', '承知いたしました。火曜15時に変更で承りました。', NULL, 'Em đã rõ. Em đã ghi nhận đổi sang thứ Ba 15h ạ.', 'formal', 1, '[承りました] Kính ngữ của 「受け取る」. Tín hiệu cho khách rằng đã ghi vào sổ.', '[承りました] 「受け取った」の謙譲語。お客様に「メモした」と伝えるサイン。', NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_05_good_example_0'), 'zun', 'male', 'BD担当', '念のため復唱させていただきます。打ち合わせを来週火曜15時に変更、でよろしいでしょうか。', NULL, 'Em xin lặp lại để chắc chắn: đổi cuộc họp sang thứ Ba tuần sau 15h, đúng không ạ?', 'formal', 2, NULL, NULL, NULL, false, true, now(), 'system'),
