  ((SELECT id FROM _ids WHERE key='conv_rule_16_good_example_0'), 'matsumoto', 'male', 'PM (白鷗株式会社)', 'いつもお世話になっております。白鷗の松本ですが、トゥアンさんお願いできますでしょうか。', NULL, 'Cảm ơn anh đã hỗ trợ. Tôi là Matsumoto bên Hakuō, nhờ em nối máy cho anh Tuấn ạ.', 'formal', 0, NULL, NULL, NULL, false, true, now(), 'system'),
