  ((SELECT id FROM _ids WHERE key='conv_rule_16_good_example_0'), 'zun', 'male', 'BD担当', '終わり次第、こちらから折り返しお電話差し上げるようお伝えしましょうか？', NULL, 'Khi xong cuộc họp em sẽ nhắn anh Tuấn gọi lại cho anh, được không ạ?', 'warm', 2, NULL, NULL, NULL, false, true, now(), 'system'),
