  ((SELECT id FROM _ids WHERE key='conv_rule_18_good_example_0'), 'matsumoto', 'male', 'PM (白鷗株式会社)', '明日の打ち合わせの時間を14時から15時に変更したい旨、お伝えください。', NULL, 'Cuộc họp ngày mai, nhờ em nhắn lại là tôi muốn đổi từ 14h sang 15h ạ.', 'formal', 0, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_18_good_example_0'), 'zun', 'male', 'BD担当', '承知いたしました。念のため復唱させていただきます。明日の打ち合わせのお時間を14時から15時へ変更とのこと、トゥアンに申し伝えます。', NULL, 'Em đã rõ ạ. Em xin phép lặp lại để chắc chắn: cuộc họp ngày mai đổi từ 14h sang 15h, em sẽ chuyển lời cho anh Tuấn ạ.', 'formal', 1, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_18_good_example_0'), 'zun', 'male', 'BD担当', 'お電話番号は090-1234-5678でよろしいでしょうか？', NULL, 'Số điện thoại của anh là 090-1234-5678 đúng không ạ?', 'formal', 2, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_18_good_example_0'), 'matsumoto', 'male', 'PM (白鷗株式会社)', 'はい、その通りです。', NULL, 'Đúng vậy ạ.', 'neutral', 3, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_18_good_example_0'), 'zun', 'male', 'BD担当', '本日10時のお電話として、責任を持って申し伝えます。', NULL, 'Em xin chịu trách nhiệm chuyển lời, ghi nhận cuộc gọi lúc 10h hôm nay ạ.', 'warm', 4, NULL, NULL, NULL, false, true, now(), 'system');
