  ((SELECT id FROM _ids WHERE key='conv_rule_19_good_example_0'), 'zun', 'male', 'BD担当', 'こちらは別の番号でございます。お手数ですが、もう一度お確かめの上おかけ直しください。', NULL, 'Đây là số khác ạ. Phiền anh kiểm tra lại số rồi gọi lại giúp ạ.', 'warm', 3, NULL, NULL, NULL, false, true, now(), 'system'),
