  ((SELECT id FROM _ids WHERE key='conv_rule_20_good_example_1'), 'zun', 'male', 'BD担当', 'ご不便をおかけしまして大変申し訳ございません。詳しくお伺いしてもよろしいでしょうか。', NULL, 'Em xin lỗi vì đã gây bất tiện cho anh ạ. Cho em hỏi chi tiết hơn được không ạ?', 'apologetic', 1, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_20_good_example_1'), 'unknown_caller', 'neutral', '発信者 (社外)', '3日前に着くはずだったのに...', NULL, 'Đáng lẽ phải đến 3 ngày trước rồi...', 'firm', 2, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_20_good_example_1'), 'zun', 'male', 'BD担当', '左様でございますか。早急に確認の上、改めてご連絡差し上げます。', NULL, 'Vâng em hiểu rồi ạ. Em sẽ kiểm tra ngay và liên hệ lại với anh sớm nhất ạ.', 'formal', 3, NULL, NULL, NULL, false, true, now(), 'system');
