INSERT INTO conversation_lines (conversation_id, speaker, speaker_gender, speaker_role, sentence, furigana, translation, politeness, order_index, notes, notes_jp, tenant_id, is_deleted, is_active, created_at, created_by) VALUES
  ((SELECT id FROM _ids WHERE key='conv_rule_21_good_example_0'), 'matsumoto', 'male', 'PM (白鷗株式会社)', 'すみません、今ホアンキエム湖の北側におります。御社まではどのように行けばよろしいでしょうか？', NULL, 'Xin lỗi, tôi đang ở phía bắc hồ Hoàn Kiếm. Tới văn phòng các bạn đi đường nào ạ?', 'formal', 0, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_21_good_example_0'), 'zun', 'male', 'BD担当', 'お電話ありがとうございます。湖の北側ですと、ハンバック (Hang Bac) 通りを北へ徒歩約5分でございます。途中、左手にBIDV銀行が見えてまいります。', NULL, 'Cảm ơn anh đã gọi ạ. Từ bắc hồ, anh đi phố Hàng Bạc về phía bắc khoảng 5 phút đi bộ. Trên đường bên trái sẽ thấy ngân hàng BIDV ạ.', 'warm', 1, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_21_good_example_0'), 'zun', 'male', 'BD担当', 'BIDVの次の角を右に曲がっていただきますと、3つ目の8階建てビルが弊社でございます。1階に『ティエンファット』の看板がございます。', NULL, 'Qua BIDV, anh rẽ phải ở góc đường tiếp theo, tòa nhà 8 tầng thứ 3 là văn phòng em ạ. Tầng 1 có biển hiệu ''Thiên Phát'' ạ.', 'warm', 2, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_21_good_example_0'), 'matsumoto', 'male', 'PM (白鷗株式会社)', 'BIDVの先を右、3つ目の8階建てビルですね。承知しました。', NULL, 'Qua BIDV rẽ phải, tòa thứ 3 cao 8 tầng nhỉ. Tôi hiểu rồi ạ.', 'neutral', 3, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_21_good_example_0'), 'zun', 'male', 'BD担当', 'お気をつけてお越しください。', NULL, 'Anh đi cẩn thận giúp em ạ.', 'warm', 4, NULL, NULL, NULL, false, true, now(), 'system');
INSERT INTO curriculum_node_content (curriculum_node_id, content_type, content_id, order_index, tenant_id, is_deleted, is_active, created_at, created_by) VALUES ((SELECT id FROM _ids WHERE key='node_rule_21'), 'conversation', (SELECT id::text FROM _ids WHERE key='conv_rule_21_good_example_0'), 1, NULL, false, true, now(), 'system');
