INSERT INTO conversation_lines (conversation_id, speaker, speaker_gender, speaker_role, sentence, furigana, translation, politeness, order_index, notes, notes_jp, tenant_id, is_deleted, is_active, created_at, created_by) VALUES
  ((SELECT id FROM _ids WHERE key='conv_rule_23_good_example_0'), 'zun', 'male', 'BD担当', 'フオン副部長、少しよろしいでしょうか。先ほど10時頃、白鷗の松本様からお電話がございました。', NULL, 'Chị Hương ơi, em xin phép một chút ạ. Khoảng 10h vừa rồi anh Matsumoto bên Hakuō có gọi điện ạ.', 'formal', 0, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_23_good_example_0'), 'fuon', 'female', '副部長', '内容は？', NULL, 'Nội dung gì vậy em?', 'neutral', 1, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_23_good_example_0'), 'zun', 'male', 'BD担当', '明日の打ち合わせを14時から15時へ変更希望とのことです。トゥアンリーダーには既に共有済みです。返信のフォローアップメールも本日中に送る予定です。', NULL, 'Anh ấy muốn dời buổi họp ngày mai từ 14h sang 15h ạ. Em đã báo anh Tuấn rồi, và sẽ gửi mail follow-up trong hôm nay ạ.', 'formal', 2, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_23_good_example_0'), 'fuon', 'female', '副部長', '分かりました。トゥアンの返答が来たらまた共有してください。', NULL, 'Chị rõ rồi. Khi anh Tuấn phản hồi em chia sẻ lại nhé.', 'warm', 3, NULL, NULL, NULL, false, true, now(), 'system');
