  ((SELECT id FROM _ids WHERE key='conv_rule_24_good_example_0'), 'zun', 'male', 'BD担当 (独り言)', '目的：4月度進捗報告。資料：開いた。メモ：書いた。環境：OK。発信。', NULL, '(Tự nhủ) Mục đích: báo cáo tiến độ tháng 4. Tài liệu: mở rồi. Note: viết rồi. Môi trường: OK. Gọi.', 'neutral', 0, NULL, NULL, NULL, false, true, now(), 'system'),
