  ((SELECT id FROM _ids WHERE key='conv_rule_31_good_example_0'), 'zun', 'male', 'BD担当', 'ティエンファット社の営業部、ズンと申します。明日の打ち合わせ資料を本日中にメールでお送りする旨、お伝えいただけますでしょうか。', NULL, 'Em là Dũng phòng kinh doanh Cty Thiên Phát ạ. Phiền chị nhắn anh Matsumoto là em sẽ gửi tài liệu họp ngày mai qua mail trong hôm nay ạ.', 'formal', 2, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_31_good_example_0'), 'zun', 'male', 'BD担当', 'ご返信は明日朝でも問題ございません。電話番号は090-1234-5678でございます。', NULL, 'Anh Matsumoto phản hồi sáng mai cũng được ạ. Số điện thoại của em là 090-1234-5678 ạ.', 'formal', 3, NULL, NULL, NULL, false, true, now(), 'system'),
