  ((SELECT id FROM _ids WHERE key='conv_rule_40_good_example_0'), 'unknown_caller', 'neutral', '発信者 (社外) (怒り)', '3回もメールしたのに返信がないんですよ！どうなってるんですか！', NULL, 'Tôi đã gửi mail 3 lần mà không có phản hồi! Là sao đây!', 'angry', 0, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_40_good_example_0'), 'zun', 'male', 'BD担当', 'はい...左様でございましたか。', NULL, 'Vâng... em hiểu rồi ạ.', 'apologetic', 1, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_40_good_example_0'), 'unknown_caller', 'neutral', '発信者 (社外)', 'もう1週間ですよ、1週間！', NULL, 'Đã 1 tuần rồi đấy, 1 tuần!', 'angry', 2, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_40_good_example_0'), 'zun', 'male', 'BD担当', 'ご返信が遅くなり、本当に申し訳ございません。すぐに状況を確認の上、本日中に必ずご回答差し上げます。', NULL, 'Em xin lỗi vì đã trả lời chậm ạ. Em sẽ kiểm tra ngay và chắc chắn trả lời anh trong hôm nay ạ.', 'apologetic', 3, NULL, NULL, NULL, false, true, now(), 'system'),
