  ((SELECT id FROM _ids WHERE key='conv_rule_42_good_example_0'), 'matsumoto', 'male', 'PM (白鷗株式会社)', '来週金曜のセミナーにご参加いただけませんか？', NULL, 'Em tham gia hội thảo thứ Sáu tuần sau được không?', 'warm', 0, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_42_good_example_0'), 'zun', 'male', 'BD担当', 'お声がけいただきありがとうございます。あいにく金曜は他の予定が入っておりまして、参加が難しい状況でございます。', NULL, 'Cảm ơn anh đã mời ạ. Đáng tiếc thứ Sáu em đã có lịch khác, em khó tham gia ạ.', 'apologetic', 1, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_42_good_example_0'), 'zun', 'male', 'BD担当', 'もし可能でしたら、後日資料を共有いただけますと幸いです。', NULL, 'Nếu được, anh chia sẻ tài liệu sau giúp em ạ.', 'warm', 2, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_42_good_example_0'), 'matsumoto', 'male', 'PM (白鷗株式会社)', '承知しました、資料お送りします。', NULL, 'Tôi hiểu rồi, tôi sẽ gửi tài liệu nhé.', 'warm', 3, NULL, NULL, NULL, false, true, now(), 'system');
