INSERT INTO conversation_lines (conversation_id, speaker, speaker_gender, speaker_role, sentence, furigana, translation, politeness, order_index, notes, notes_jp, tenant_id, is_deleted, is_active, created_at, created_by) VALUES
  ((SELECT id FROM _ids WHERE key='conv_rule_43_good_example_0'), 'zun', 'male', 'BD担当', 'お忙しいところ恐れ入ります。明日10時のお打ち合わせの件でお電話いたしました。', NULL, 'Em xin phép làm phiền lúc anh đang bận ạ. Em gọi về việc cuộc họp 10h ngày mai ạ.', 'formal', 0, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_43_good_example_0'), 'zun', 'male', 'BD担当', '申し訳ございませんが、急遽弊社のトゥアンの出張が入りまして、日程を変更させていただきたくお願い申し上げます。', NULL, 'Em xin lỗi anh, anh Tuấn đột xuất phải đi công tác, em xin phép dời lịch ạ.', 'apologetic', 1, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_43_good_example_0'), 'zun', 'male', 'BD担当', '代替案として、明後日の14時、もしくは来週月曜の10時はいかがでしょうか？', NULL, 'Em xin đề xuất 2 phương án: ngày kia 14h, hoặc thứ Hai tuần sau 10h, anh thấy thế nào ạ?', 'formal', 2, NULL, NULL, NULL, false, true, now(), 'system'),
  ((SELECT id FROM _ids WHERE key='conv_rule_43_good_example_0'), 'matsumoto', 'male', 'PM (白鷗株式会社)', 'では、来週月曜10時でお願いします。', NULL, 'Vậy thứ Hai tuần sau 10h nhé.', 'warm', 3, NULL, NULL, NULL, false, true, now(), 'system'),
