  ((SELECT id FROM _ids WHERE key='conv_rule_44_good_example_0'), 'zun', 'male', 'BD担当', 'お忙しいところ恐れ入ります。残念なお知らせがございまして、お電話いたしました。', NULL, 'Em xin lỗi làm phiền lúc anh đang bận ạ. Em có tin không hay cần báo nên xin phép gọi anh ạ.', 'urgent', 0, NULL, NULL, NULL, false, true, now(), 'system'),
