  ((SELECT id FROM _ids WHERE key='conv_rule_44_good_example_0'), 'zun', 'male', 'BD担当', '対応として、すでにロールバックを実行中で、30分以内に復旧の見込みでございます。', NULL, 'Bên em đang thực thi rollback, dự kiến khôi phục trong 30 phút ạ.', 'firm', 3, NULL, NULL, NULL, false, true, now(), 'system'),
