WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, title, title_jp, sentence, translation, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_16'), 'Câu chốt: 折り返し提案', '折り返し提案', '終わり次第、折り返しお電話差し上げるようお伝えしましょうか？', 'Khi xong em sẽ nhắn gọi lại cho anh, được không ạ?', 2, true, NULL, false, true, now(), 'system') RETURNING id)
