WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, level, title, title_jp, situation, situation_jp, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, false, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_17'), 'BJT-J3', 'TỐT', '良い例', 'Hold 50 giây thì quay lại đề xuất gọi lại — thể hiện tôn trọng thời gian của khách.', '保留50秒で一旦戻り、折り返しを提案。相手の時間を尊重する姿勢が伝わる。', 1, true, NULL, false, true, now(), 'system') RETURNING id)
