WITH ins AS (INSERT INTO questions (user_id, is_system, question_type, content_type, level, question, sentence, sentence_translation, general_explanation, selection_type, base_difficulty, skill_category, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'multiple_choice', 'curriculum_node', 'J3', '保留が1分を超えそうな時、最も適切なのは？', '保留が1分を超えそうな時、最も適切なのは？', NULL, 'Quá 1 phút phải quay lại line. Tôn trọng thời gian của đối phương là nguyên tắc cơ bản.
