-- Rule 18: 5 yếu tố bắt buộc khi take message
WITH ins AS (INSERT INTO curriculum_node (curriculum_id, parent_id, node_type, node_title, note_title_jp, node_definition, node_definition_jp, node_extra, node_conclusion, node_conclusion_jp, order_index, access_level, tenant_id, is_deleted, is_active, created_at, created_by) VALUES ((SELECT id FROM _ids WHERE key='curriculum'), NULL, 'rule', '5 yếu tố bắt buộc khi take message', '伝言メモの5要素', 'Anh Matsumoto để lại lời nhắn cho anh Tuấn. Em Dũng ghi đủ 5 yếu tố (ai/cty/số/nội dung/giờ) và lặp lại xác nhận.', '松本PMがトゥアン宛の伝言を残す。ズンが必須5要素（誰・会社・番号・用件・時刻）を確実にメモして復唱で確認する場面。', '{"related_rules": ["rule_14", "rule_16", "rule_31"]}', 'Em xin phép lặp lại để chắc chắn ạ.', '責任を持って申し伝えます。', 18, 'paid', NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, level, title, title_jp, situation, situation_jp, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, false, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_18'), 'BJT-J3', 'TỐT', '良い例', 'Trình tự: nội dung → lặp lại → xác nhận số → tuyên bố trách nhiệm — đủ 5 yếu tố. 「責任を持って」 là điểm quyết định lòng tin.', '用件→復唱→番号確認→責任宣言の順で5要素全てカバー。「責任を持って」が信頼の決め手。', 1, true, NULL, false, true, now(), 'system') RETURNING id)
