WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, title, title_jp, sentence, translation, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_18'), 'Câu chốt: 伝言締めくくり・信頼形成', '伝言締めくくり・信頼形成', '責任を持って申し伝えます。', 'Em xin chịu trách nhiệm chuyển lời ạ.', 1, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO questions (user_id, is_system, question_type, content_type, level, question, sentence, sentence_translation, general_explanation, selection_type, base_difficulty, skill_category, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'multiple_choice', 'curriculum_node', 'J2', '伝言メモに必須でない要素はどれか？', '伝言メモに必須でない要素はどれか？', NULL, '5 yếu tố bắt buộc là tên/cty/số/nội dung/giờ. Tuổi không cần thiết.
