WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, level, title, title_jp, situation, situation_jp, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, false, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_19'), 'BJT-J3', 'TỐT', '良い例', 'Dùng 「お間違いではないでしょうか」 — cách hỏi vòng. Không trách đối phương, mời họ kiểm tra số, kết thúc bằng câu chào từ phía mình mới chuyên nghiệp.', '「お間違いではないでしょうか」と婉曲に確認。相手を責めず番号確認を促し、最後にこちらからも挨拶で締めるのがプロ。', 1, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, title, title_jp, sentence, translation, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_19'), 'Câu chốt: 間違い電話の標準応対', '間違い電話の標準応対', 'お間違いではないでしょうか？お手数ですが、お確かめの上おかけ直しください。', 'Có lẽ anh/chị nhầm số. Phiền anh/chị kiểm tra lại rồi gọi lại giúp ạ.', 0, true, NULL, false, true, now(), 'system') RETURNING id)
