-- Rule 20: Bước đầu xử lý phàn nàn qua phone
WITH ins AS (INSERT INTO curriculum_node (curriculum_id, parent_id, node_type, node_title, note_title_jp, node_definition, node_definition_jp, node_extra, node_conclusion, node_conclusion_jp, order_index, access_level, tenant_id, is_deleted, is_active, created_at, created_by) VALUES ((SELECT id FROM _ids WHERE key='curriculum'), NULL, 'rule', 'Bước đầu xử lý phàn nàn qua phone', 'クレーム電話の最初の対応', 'Khách phàn nàn vì hàng chưa đến. Tình huống thực hành bước đầu: lắng nghe + xin lỗi cảm xúc trước khi giải thích.', '顧客から商品未着のクレーム電話。最初の対応で『傾聴と感情への謝罪』を実践する場面。', '{"related_rules": ["rule_40", "rule_41", "rule_45"]}', 'Em xin lỗi vì đã gây bất tiện. Cho em hỏi chi tiết hơn được không ạ?', 'ご不便をおかけしまして大変申し訳ございません。', 20, 'paid', NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, level, title, title_jp, situation, situation_jp, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, false, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_20'), 'BJT-J3', 'XẤU', '悪い例', 'Giải thích sự kiện trước nghe như ''biện minh'' — làm khách thêm tức. Sai điển hình.', '事実説明を先に出すと『言い訳』に聞こえる。怒りを増幅させる典型的失敗。', 1, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, level, title, title_jp, situation, situation_jp, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, false, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_20'), 'BJT-J3', 'TỐT', '良い例', '「ご不便をおかけして」 = xin lỗi vì cảm xúc bất tiện, không phải xin lỗi sự kiện. Sau đó mới hỏi chi tiết để xác minh.', '『ご不便をおかけして』で感情に寄り添う謝罪。事実の謝罪ではない。次に詳細聴取で初めて事実確認に入る。', 2, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, title, title_jp, sentence, translation, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_20'), 'Câu chốt: クレーム第一声・傾聴と感情謝罪', 'クレーム第一声・傾聴と感情謝罪', 'ご不便をおかけしまして大変申し訳ございません。詳しくお伺いしてもよろしいでしょうか。', 'Em xin lỗi vì đã gây bất tiện. Cho em hỏi chi tiết hơn được không ạ?', 0, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO questions (user_id, is_system, question_type, content_type, level, question, sentence, sentence_translation, general_explanation, selection_type, base_difficulty, skill_category, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'multiple_choice', 'curriculum_node', 'J2', 'クレーム電話の最初の対応として最も適切なのは？', 'クレーム電話の最初の対応として最も適切なのは？', NULL, 'Nguyên tắc: nghe → xin lỗi cảm xúc → xác minh → giải pháp. Giải thích trước nghe như biện minh.
