WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, level, title, title_jp, situation, situation_jp, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, false, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_21'), 'BJT-J3', 'TỐT', '良い例', 'Xác nhận vị trí → mốc (BIDV) → hướng (rẽ phải) → đặc điểm tòa nhà (8 tầng, biển hiệu). Kết bằng 「お気をつけて」 lịch sự.', '現在地確認→目印（BIDV銀行）→方向（右折）→建物特徴（8階建て・看板）の順で具体的。最後に『お気をつけて』で締める。', 1, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, title, title_jp, sentence, translation, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_21'), 'Câu chốt: 道案内の標準フォーマット', '道案内の標準フォーマット', '〇〇を目印に、〇〇通りを徒歩約〇分でございます。', 'Lấy 〇〇 làm mốc, đi phố 〇〇 khoảng 〇 phút đi bộ ạ.', 0, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO questions (user_id, is_system, question_type, content_type, level, question, sentence, sentence_translation, general_explanation, selection_type, base_difficulty, skill_category, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'multiple_choice', 'curriculum_node', 'J3', '訪問先案内で最も避けるべき表現は？', '訪問先案内で最も避けるべき表現は？', NULL, '「適当に」 (đại khái) quá mơ hồ. Hướng dẫn phải cụ thể: mốc + hướng + khoảng cách.
