「適当に」は曖昧で道案内NG。具体的な目印・方向・距離が原則。', 'single', 3, '場面把握', NULL, false, true, now(), 'system') RETURNING id)

-- Rule 22: Thứ tự gác máy: khách trước, mình sau
WITH ins AS (INSERT INTO curriculum_node (curriculum_id, parent_id, node_type, node_title, note_title_jp, node_definition, node_definition_jp, node_extra, node_conclusion, node_conclusion_jp, order_index, access_level, tenant_id, is_deleted, is_active, created_at, created_by) VALUES ((SELECT id FROM _ids WHERE key='curriculum'), NULL, 'rule', 'Thứ tự gác máy: khách trước, mình sau', '受話器を置くタイミング', 'Thứ tự cúp máy: khách/cấp trên trước, mình sau. Cúp trước = thiếu tôn trọng.', '電話を切る順序は『相手（顧客・上司）→自分』の順が鉄則。先に切ると失礼に当たる。', '{"related_rules": ["rule_01", "rule_11", "rule_35"]}', 'Hôm nay cảm ơn anh đã gọi ạ. Em xin phép cúp máy ạ.', '相手が切ってから、静かに受話器を置く', 22, 'paid', NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, level, title, title_jp, situation, situation_jp, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, false, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_22'), 'BJT-J3', 'TỐT', '良い例', 'Sau 「失礼いたします」, đợi nghe tiếng đối phương cúp + chờ 2-3 giây rồi đặt nhẹ. Đặt mạnh = vi phạm lễ nghi.', '「失礼いたします」で締めた後、相手の切る音を確認してから2-3秒待って静かに置く。受話器を強く置く音はマナー違反。', 1, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, title, title_jp, sentence, translation, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_22'), 'Câu chốt: 電話終了の標準フレーズ', '電話終了の標準フレーズ', '本日はお電話ありがとうございました。失礼いたします。', 'Hôm nay cảm ơn anh đã gọi ạ. Em xin phép cúp máy ạ.', 0, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO questions (user_id, is_system, question_type, content_type, level, question, sentence, sentence_translation, general_explanation, selection_type, base_difficulty, skill_category, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'multiple_choice', 'curriculum_node', 'J4', '顧客との電話で、受話器を置くタイミングは？', '顧客との電話で、受話器を置くタイミングは？', NULL, 'Khách/cấp trên cúp trước, mình cúp sau là quy tắc cơ bản.
