顧客や上司が切ってから自分が切るのが基本マナー。', 'single', 2, '場面把握', NULL, false, true, now(), 'system') RETURNING id)

-- Rule 23: Báo lại nội bộ sau cuộc gọi quan trọng
WITH ins AS (INSERT INTO curriculum_node (curriculum_id, parent_id, node_type, node_title, note_title_jp, node_definition, node_definition_jp, node_extra, node_conclusion, node_conclusion_jp, order_index, access_level, tenant_id, is_deleted, is_active, created_at, created_by) VALUES ((SELECT id FROM _ids WHERE key='curriculum'), NULL, 'rule', 'Báo lại nội bộ sau cuộc gọi quan trọng', '受電後の社内報告', 'Sau khi nhận điện anh Matsumoto, em Dũng báo cáo trực tiếp chị Hương phó phòng. Truyền đạt gọn 4 yếu tố: giờ/người gọi/nội dung/bước tiếp.', 'ズンが白鷗・松本からの電話を受けた後、フオン副部長に直接報告する場面。日時・発信者・用件・次アクションの4要素を簡潔に伝える。', '{"related_rules": ["rule_18", "rule_51", "rule_59"]}', 'Khoảng 〇 giờ vừa rồi, anh/chị 〇〇 có gọi điện ạ.', '先ほど〇時頃、〇〇様からお電話がございました。', 23, 'paid', NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, level, title, title_jp, situation, situation_jp, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, false, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_23'), 'BJT-J3', 'TỐT', '良い例', 'Báo theo trình tự ''giờ → người gọi → nội dung → bước tiếp'' trong 30 giây. Sếp nắm thông tin cần nhanh nhất.', '『日時→発信者→用件→次アクション』の順で30秒以内に報告。先輩は欲しい情報をすぐ把握できる。', 1, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, title, title_jp, sentence, translation, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_23'), 'Câu chốt: 受電後社内報告の冒頭', '受電後社内報告の冒頭', '先ほど〇時頃、〇〇様からお電話がございました。', 'Khoảng 〇 giờ vừa rồi, anh/chị 〇〇 có gọi điện ạ.', 0, true, NULL, false, true, now(), 'system') RETURNING id)
