報告の核は『誰から何の用件で、次に何をすべきか』。', 'single', 3, '場面把握', NULL, false, true, now(), 'system') RETURNING id)

-- Rule 24: Checklist trước khi nhấn gọi
WITH ins AS (INSERT INTO curriculum_node (curriculum_id, parent_id, node_type, node_title, note_title_jp, node_definition, node_definition_jp, node_extra, node_conclusion, node_conclusion_jp, order_index, access_level, tenant_id, is_deleted, is_active, created_at, created_by) VALUES ((SELECT id FROM _ids WHERE key='curriculum'), NULL, 'rule', 'Checklist trước khi nhấn gọi', '発信前のチェックリスト', 'Em Dũng tự kiểm trước khi gọi báo cáo tiến độ tháng 4 cho anh Matsumoto, sau đó nhấn gọi và mở lời.', 'ズンが松本PMへ4月度進捗報告のため発信する直前の自己点検と、発信時の第一声。', '{"related_rules": ["rule_25", "rule_26", "rule_28"]}', 'Cảm ơn anh đã hỗ trợ. Em là Dũng phòng kinh doanh Cty Thiên Phát ạ. Anh/chị 〇〇 có ở văn phòng không ạ?', '目的・時間・資料・メモ・環境', 24, 'paid', NULL, false, true, now(), 'system') RETURNING id)
