WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, title, title_jp, sentence, translation, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_24'), 'Câu chốt: 発信時の標準フォーマット', '発信時の標準フォーマット', 'お世話になっております。ティエンファット社、営業部のズンでございます。〇〇様のお席はございますでしょうか？', 'Cảm ơn anh đã hỗ trợ. Em là Dũng phòng kinh doanh Cty Thiên Phát ạ. Anh/chị 〇〇 có ở văn phòng không ạ?', 0, true, NULL, false, true, now(), 'system') RETURNING id)
