-- Rule 26: Format giới thiệu khi gọi đi
WITH ins AS (INSERT INTO curriculum_node (curriculum_id, parent_id, node_type, node_title, note_title_jp, node_definition, node_definition_jp, node_extra, node_conclusion, node_conclusion_jp, order_index, access_level, tenant_id, is_deleted, is_active, created_at, created_by) VALUES ((SELECT id FROM _ids WHERE key='curriculum'), NULL, 'rule', 'Format giới thiệu khi gọi đi', '発信時の名乗りフォーマット', 'Em Dũng gọi vào số đại diện Hakuō. Với lễ tân, thực hiện 3 yếu tố: chào → tự xưng → nhờ nối máy.', 'ズンが白鷗社代表番号に発信。受付に対して①挨拶②自己紹介③取次依頼の3要素を実践する場面。', '{"related_rules": ["rule_24", "rule_25", "rule_27"]}', 'Em là Dũng phòng kinh doanh Cty Thiên Phát ạ. Phiền chị, anh/chị 〇〇 có ở văn phòng không ạ?', 'ティエンファット社、営業部のズンと申します。〇〇様はいらっしゃいますでしょうか？', 26, 'paid', NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, level, title, title_jp, situation, situation_jp, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, false, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_26'), 'BJT-J3', 'TỐT', '良い例', '「と申します」 khiêm nhường, 「恐れ入りますが」 lời mở rào, 「いらっしゃいますでしょうか」 kính ngữ cao. Với lễ tân vẫn giữ lễ độ.', '『と申します』で謙譲、『恐れ入りますが』で前置き、『いらっしゃいますでしょうか』で最高敬語。受付に対しても同じ礼儀を保つ。', 1, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, title, title_jp, sentence, translation, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_26'), 'Câu chốt: 発信名乗り＋取次依頼の標準', '発信名乗り＋取次依頼の標準', 'ティエンファット社、営業部のズンと申します。恐れ入りますが、〇〇様はいらっしゃいますでしょうか？', 'Em là Dũng phòng kinh doanh Cty Thiên Phát ạ. Phiền chị, anh/chị 〇〇 có ở văn phòng không ạ?', 0, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO questions (user_id, is_system, question_type, content_type, level, question, sentence, sentence_translation, general_explanation, selection_type, base_difficulty, skill_category, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'multiple_choice', 'curriculum_node', 'J3', '発信時の自己紹介で正しい謙譲表現は？', '発信時の自己紹介で正しい謙譲表現は？', NULL, 'Bên gọi đi tự xưng dùng khiêm nhường 「と申します」. Bên nhận máy dùng 「でございます」.
