発信側の自己紹介は謙譲語『と申します』。受電側は『でございます』。', 'single', 3, '表現読解', NULL, false, true, now(), 'system') RETURNING id)

-- Rule 27: Hỏi đối phương có rảnh trước khi vào việc
WITH ins AS (INSERT INTO curriculum_node (curriculum_id, parent_id, node_type, node_title, note_title_jp, node_definition, node_definition_jp, node_extra, node_conclusion, node_conclusion_jp, order_index, access_level, tenant_id, is_deleted, is_active, created_at, created_by) VALUES ((SELECT id FROM _ids WHERE key='curriculum'), NULL, 'rule', 'Hỏi đối phương có rảnh trước khi vào việc', '相手の都合を最初に確認', 'Gọi đi xong trước khi vào việc luôn hỏi 「お時間よろしいでしょうか」. Nói rõ thời gian cần (5 phút) càng lịch sự hơn.', '発信後、本題に入る前に必ず『お時間よろしいでしょうか』で都合確認。所要時間（5分など）を明示するとさらに丁寧。', '{"related_rules": ["rule_25", "rule_26", "rule_28"]}', 'Bây giờ em xin khoảng 〇 phút có tiện anh không ạ?', '今、〇分ほどお時間よろしいでしょうか？', 27, 'paid', NULL, false, true, now(), 'system') RETURNING id)
