WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, level, title, title_jp, situation, situation_jp, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, false, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_27'), 'BJT-J3', 'Biến thể — Khi đối phương bận', 'バリエーション — 相手が忙しい場合', 'Nếu bị từ chối, đề xuất giờ cụ thể để đặt lại. Chỉ nói 「後ほど」 thì mơ hồ.', '断られたら具体的な時間を提案して再アポ。『後ほど』だけでは曖昧。', 2, true, NULL, false, true, now(), 'system') RETURNING id)
