WITH ins AS (INSERT INTO curriculum_node (curriculum_id, parent_id, node_type, node_title, note_title_jp, node_definition, node_definition_jp, node_extra, node_conclusion, node_conclusion_jp, order_index, access_level, tenant_id, is_deleted, is_active, created_at, created_by) VALUES ((SELECT id FROM _ids WHERE key='curriculum'), NULL, 'rule', 'Voicemail 30 giây format', '留守番電話に残すメッセージ', 'Anh Matsumoto vắng, máy chuyển voicemail. Em Dũng để lại tin nhắn 30 giây với 4 yếu tố: tự xưng / việc / số gọi lại / chào.', '松本PMが不在で留守電に切り替わった場面。30秒以内・4要素（名乗り・要件・折り返し情報・挨拶）でメッセージを残す。', '{"related_rules": ["rule_50", "rule_32"]}', 'Lúc nào rảnh anh gọi lại số 〇〇 giúp em ạ.', 'お手すきの際に〇〇〇〇までお電話いただけますと幸いです。', 49, 'paid', NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, level, title, title_jp, situation, situation_jp, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, false, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_49'), 'BJT-J3', 'TỐT — Voicemail', '良い例 (Voicemail)', 'Đủ 4 yếu tố trong 30 giây, có số gọi lại và giờ tiện. Đối phương đủ thông tin để quyết định.', '4要素を漏れなく30秒以内に収め、折り返し番号と対応可能時間を明示。相手は判断材料が揃っている。', 1, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, title, title_jp, sentence, translation, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_49'), 'Câu chốt: 留守電折り返し依頼', '留守電折り返し依頼', 'お手すきの際に〇〇〇〇までお電話いただけますと幸いです。', 'Lúc nào rảnh anh gọi lại số 〇〇 giúp em ạ.', 0, true, NULL, false, true, now(), 'system') RETURNING id)
