-- Rule 50: Sau khi nghe voicemail — gọi lại trong 24h
WITH ins AS (INSERT INTO curriculum_node (curriculum_id, parent_id, node_type, node_title, note_title_jp, node_definition, node_definition_jp, node_extra, node_conclusion, node_conclusion_jp, order_index, access_level, tenant_id, is_deleted, is_active, created_at, created_by) VALUES ((SELECT id FROM _ids WHERE key='curriculum'), NULL, 'rule', 'Sau khi nghe voicemail — gọi lại trong 24h', '留守番電話を聞いた後の対応', 'Em Dũng nghe voicemail anh Matsumoto và gọi lại. Dùng 「拝聴いたしました」 để cho biết đã chú ý.', '松本PMが残した留守電を聞いて折り返し電話をする場面。『拝聴いたしました』で確認したことを示す。', '{"related_rules": ["rule_49", "rule_32"]}', 'Em đã nghe lời nhắn anh để lại ạ.', 'お電話いただきましたメッセージを確認いたしました。', 50, 'paid', NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, level, title, title_jp, situation, situation_jp, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, false, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_50'), 'BJT-J3', 'TỐT', '良い例', '「拝聴いたしました」 khiêm nhường + tóm tắt nội dung = đối phương biết bạn đã nghe kỹ.', '『拝聴いたしました』で謙譲、メッセージ要旨を要約することで相手は『ちゃんと聞いた』と分かる。', 1, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, title, title_jp, sentence, translation, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_50'), 'Câu chốt: 留守電応答の冒頭', '留守電応答の冒頭', 'お電話いただきましたメッセージを確認いたしました。', 'Em đã nghe lời nhắn anh để lại ạ.', 0, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO questions (user_id, is_system, question_type, content_type, level, question, sentence, sentence_translation, general_explanation, selection_type, base_difficulty, skill_category, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'multiple_choice', 'curriculum_node', 'J3', '留守電を聞いて折り返す時の最も適切な言い方は？', '留守電を聞いて折り返す時の最も適切な言い方は？', NULL, 'Voicemail dùng 「確認いたしました / 承りました」 là chuẩn. 「拝聴」 dành cho nội dung trang trọng (bài giảng, diễn văn) — quá nặng.
---
留守電には『確認いたしました』『承りました』が標準。『拝聴』は講演など重みのある内容向けで過剰。', 'single', 3, '表現読解', NULL, false, true, now(), 'system') RETURNING id)

-- Rule 51: Phone xong gửi tóm tắt qua mail
WITH ins AS (INSERT INTO curriculum_node (curriculum_id, parent_id, node_type, node_title, note_title_jp, node_definition, node_definition_jp, node_extra, node_conclusion, node_conclusion_jp, order_index, access_level, tenant_id, is_deleted, is_active, created_at, created_by) VALUES ((SELECT id FROM _ids WHERE key='curriculum'), NULL, 'rule', 'Phone xong gửi tóm tắt qua mail', '電話後のフォローアップメール', 'Sau cuộc gọi quan trọng, cuối điện thoại nói rõ sẽ gửi mail follow-up trong 1h.', '重要通話後、1時間以内にフォローアップメールを送る約束を電話の最後で明示する場面。', '{"related_rules": ["rule_35", "rule_23"]}', 'Em sẽ tổng hợp gửi mail follow-up trong hôm nay ạ.', '本日中にフォローアップメールでまとめてお送りいたします。', 51, 'paid', NULL, false, true, now(), 'system') RETURNING id)
