-- Rule 52: Conference call / Zoom / Teams etiquette
WITH ins AS (INSERT INTO curriculum_node (curriculum_id, parent_id, node_type, node_title, note_title_jp, node_definition, node_definition_jp, node_extra, node_conclusion, node_conclusion_jp, order_index, access_level, tenant_id, is_deleted, is_active, created_at, created_by) VALUES ((SELECT id FROM _ids WHERE key='curriculum'), NULL, 'rule', 'Conference call / Zoom / Teams etiquette', 'オンライン会議の電話作法', 'Em Dũng phát biểu trong họp online. Mở đầu bằng confirm âm thanh, tự xưng khi phát biểu, đánh dấu kết thúc.', 'オンライン会議でズンが発表する場面。冒頭の音声確認、発言時の名乗り、終了の合図を実践。', '{"related_rules": ["rule_53", "rule_54", "rule_55"]}', 'Mọi người nghe được tiếng em không ạ?', '〇〇のズンより〇〇についてご報告いたします。', 52, 'paid', NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, level, title, title_jp, situation, situation_jp, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, false, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_52'), 'BJT-J3', 'TỐT', '良い例', 'Mở 「音声は聞こえておりますでしょうか」, vào việc 「ズンより〜ご報告いたします」, kết 「以上です」. Bắt buộc khi không có hình.', '『音声は聞こえておりますでしょうか』で開始確認、『ズンより〜ご報告いたします』で発言開始、『以上です』で終了。視覚情報なしの会議で必須。', 1, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, title, title_jp, sentence, translation, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_52'), 'Câu chốt: オンライン会議冒頭の音声確認', 'オンライン会議冒頭の音声確認', '皆様、音声は聞こえておりますでしょうか？', 'Mọi người nghe được tiếng em không ạ?', 0, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO questions (user_id, is_system, question_type, content_type, level, question, sentence, sentence_translation, general_explanation, selection_type, base_difficulty, skill_category, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'multiple_choice', 'curriculum_node', 'J3', 'オンライン会議の冒頭で必須なのは？', 'オンライン会議の冒頭で必須なのは？', NULL, 'Không có hình nên cần confirm âm thanh + tự xưng để xác định ai.
---
視覚情報なしのため、音声確認と名乗りで参加者を識別する。', 'single', 3, '場面把握', NULL, false, true, now(), 'system') RETURNING id)

