-- Rule 54: Mute/unmute etiquette
WITH ins AS (INSERT INTO curriculum_node (curriculum_id, parent_id, node_type, node_title, note_title_jp, node_definition, node_definition_jp, node_extra, node_conclusion, node_conclusion_jp, order_index, access_level, tenant_id, is_deleted, is_active, created_at, created_by) VALUES ((SELECT id FROM _ids WHERE key='curriculum'), NULL, 'rule', 'Mute/unmute etiquette', 'マイクオフ・オンの礼儀', 'Trong họp online — phát biểu mới unmute, xong thì mute. Mở lời bằng tự xưng.', 'オンライン会議で発言時のみアンミュート、終わったらミュート。発言冒頭に名乗りを付ける。', '{"related_rules": ["rule_52", "rule_57"]}', 'Em Dũng bên 〇〇 ạ, em xin hỏi 1 điểm được không ạ?', '1点よろしいでしょうか？', 54, 'paid', NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, level, title, title_jp, situation, situation_jp, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, false, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_54'), 'BJT-J3', 'TỐT', '良い例', 'Sau khi unmute chờ 0.5s để âm thanh sync. Tự xưng → báo có câu hỏi → câu hỏi.', 'アンミュート後0.5秒待機で音声同期確保。名乗り→質問予告→質問本文の流れ。', 1, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, title, title_jp, sentence, translation, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_54'), 'Câu chốt: アンミュート後の発言冒頭', 'アンミュート後の発言冒頭', '〇〇のズンですが、1点よろしいでしょうか？', 'Em Dũng bên 〇〇 ạ, em xin hỏi 1 điểm được không ạ?', 0, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO questions (user_id, is_system, question_type, content_type, level, question, sentence, sentence_translation, general_explanation, selection_type, base_difficulty, skill_category, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'multiple_choice', 'curriculum_node', 'J4', 'オンライン会議で発言しない時のマイクは？', 'オンライン会議で発言しない時のマイクは？', NULL, 'Không nói thì mute — tránh tạp âm là nguyên tắc cơ bản.
