WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, title, title_jp, sentence, translation, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_56'), 'Câu chốt: 録音許可の標準フレーズ', '録音許可の標準フレーズ', '録音と自動文字起こしをさせていただきたく存じます。ご了承いただけますでしょうか？', 'Em xin phép ghi âm và auto-transcribe ạ. Anh/chị có đồng ý không ạ?', 0, true, NULL, false, true, now(), 'system') RETURNING id)
