-- Rule 57: Take floor in conference call — interrupt khéo
WITH ins AS (INSERT INTO curriculum_node (curriculum_id, parent_id, node_type, node_title, note_title_jp, node_definition, node_definition_jp, node_extra, node_conclusion, node_conclusion_jp, order_index, access_level, tenant_id, is_deleted, is_active, created_at, created_by) VALUES ((SELECT id FROM _ids WHERE key='curriculum'), NULL, 'rule', 'Take floor in conference call — interrupt khéo', '電話会議で発言を取る', 'Sau khi người trước nói xong, em Dũng xin phát biểu. Dùng 「恐れ入ります」 + tự xưng để xin lượt.', '前話者の発言終了後、ズンが発言を取りに行く場面。『恐れ入ります』＋名乗りで割り込まずに floor を取る。', '{"related_rules": ["rule_52", "rule_54"]}', 'Em xin lỗi, em Dũng bên 〇〇 ạ. Em xin phát biểu được không ạ?', '恐れ入ります、〇〇のズンです。発言よろしいでしょうか？', 57, 'paid', NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, level, title, title_jp, situation, situation_jp, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, false, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_57'), 'BJT-J3', 'TỐT', '良い例', 'Đợi người trước kết thúc 「〜と言えるでしょう」 rồi xen vào. Hỏi 「発言よろしいでしょうか」 = xin phép.', '前話者の文末『〜と言えるでしょう』を待ってから割り込む。『発言よろしいでしょうか』で許可取得型。', 1, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, title, title_jp, sentence, translation, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_57'), 'Câu chốt: 発言取得の標準フレーズ', '発言取得の標準フレーズ', '恐れ入ります、〇〇のズンです。発言よろしいでしょうか？', 'Em xin lỗi, em Dũng bên 〇〇 ạ. Em xin phát biểu được không ạ?', 0, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO questions (user_id, is_system, question_type, content_type, level, question, sentence, sentence_translation, general_explanation, selection_type, base_difficulty, skill_category, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'multiple_choice', 'curriculum_node', 'J3', 'オンライン会議で発言を取る時の最良の方法は？', 'オンライン会議で発言を取る時の最良の方法は？', NULL, 'Tôn trọng người trước, xin phép trước khi nói.
---
前話者を尊重し許可取得型で発言する。', 'single', 3, '場面把握', NULL, false, true, now(), 'system') RETURNING id)

-- Rule 58: Hybrid meeting — vừa offline vừa online
WITH ins AS (INSERT INTO curriculum_node (curriculum_id, parent_id, node_type, node_title, note_title_jp, node_definition, node_definition_jp, node_extra, node_conclusion, node_conclusion_jp, order_index, access_level, tenant_id, is_deleted, is_active, created_at, created_by) VALUES ((SELECT id FROM _ids WHERE key='curriculum'), NULL, 'rule', 'Hybrid meeting — vừa offline vừa online', 'ハイブリッド会議', 'Tại VN có Dũng + Tuấn offline, anh Matsumoto online. Em Dũng làm moderator, đảm bảo người online không bị bỏ rơi.', 'ベトナム本社にズン・トゥアンが集まり、松本PMはオンライン参加。ズンがモデレーターとしてオンライン参加者を取り残さない進行を実演。', '{"related_rules": ["rule_52", "rule_57"]}', 'Phía online cho em xin ý kiến với ạ.', 'オンラインからもお声をいただけますでしょうか。', 58, 'paid', NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, level, title, title_jp, situation, situation_jp, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, false, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_58'), 'BJT-J3', 'TỐT', '良い例', 'Gọi tên người online, tóm tắt phát biểu của phòng cho online. Cả hai bên đều có cảm giác tham gia.', 'オンライン参加者を名指しで呼び、会場の発言を要約して伝える。両者の参加感を保つ。', 1, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO conversations (user_id, is_single_line, content_type, content_id, title, title_jp, sentence, translation, order_index, is_system, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'curriculum_node', (SELECT id::text FROM _ids WHERE key='node_rule_58'), 'Câu chốt: ハイブリッド会議でオンライン参加者を巻き込む', 'ハイブリッド会議でオンライン参加者を巻き込む', 'オンラインからもお声をいただけますでしょうか。', 'Phía online cho em xin ý kiến với ạ.', 0, true, NULL, false, true, now(), 'system') RETURNING id)
WITH ins AS (INSERT INTO questions (user_id, is_system, question_type, content_type, level, question, sentence, sentence_translation, general_explanation, selection_type, base_difficulty, skill_category, tenant_id, is_deleted, is_active, created_at, created_by) VALUES (NULL, true, 'multiple_choice', 'curriculum_node', 'J2', 'ハイブリッド会議で最も注意すべきは？', 'ハイブリッド会議で最も注意すべきは？', NULL, 'Thách thức lớn nhất của hybrid là không để người online cảm thấy bị bỏ rơi.
